import 'dart:convert';
import 'dart:typed_data';

class FeatureArt {
  static final Map<String, Uint8List> _cache = {};

  static Uint8List bytesFor(String key) {
    return _cache.putIfAbsent(key, () => base64Decode(_art[key]!));
  }

  static const Map<String, String> _art = {
    'sos': '',
    'fakeCall': '',
    'liveLocation': '',
    'contacts': '',
    'helpline': '',
    'police': '',
    'tips': '',
    'journey': '',
    'profile': '',
  };
}
